def load_image(encoded_string, size):
    image_bytes = base64.b64decode(encoded_string)
    image = Image.open(BytesIO(image_bytes)).convert("RGBA")
    image = image.resize((size, size), Image.LANCZOS)
    return ImageTk.PhotoImage(image)

