from random import choice  # Solely to choose which side you're going on if you pick random.

class AIOptionsUI:

    def __init__(self, window):
        self.Tk_UI = Frame(master=window, bg="#A56E54")  # Creates the UI
        self.Tk_UI.pack(fill="both", expand="True")
        self.create_ui()
        self.total_chosen_options = []
        self.ai_chosen_option = -1

    def create_ui(self):
        global time_allowed_per_move

        home_button = Button(self.Tk_UI, bg="white", image=home_button_image, command=lambda: return_to_main_ui(self))
        home_button.pack(anchor="nw", padx=8, pady=8)

        ai_title_label = Label(self.Tk_UI, text="AI Settings", font=("Helvetica", 36), bg='#A56E54', fg='#ECE7BD')
        ai_title_label.pack(pady=40)

        side_choice_container = Frame(master=self.Tk_UI, bg='#A97148')
        side_choice_container.pack(pady=40)

        side_choice_btn1 = Button(side_choice_container, bg="white", image=larger_white_king_image, command=lambda: self.activate_button(side_choice_btn1, 0))
        side_choice_btn2 = Button(side_choice_container, bg="white", image=mixed_white_black_king_image, command=lambda: self.activate_button(side_choice_btn2, 1))
        side_choice_btn3 = Button(side_choice_container, bg="white", image=larger_black_king_image, command=lambda: self.activate_button(side_choice_btn3, 2))

        side_choice_btn1.grid(row=0, column=0, padx=20)
        side_choice_btn2.grid(row=0, column=1, padx=20)
        side_choice_btn3.grid(row=0, column=2, padx=20)

        time_frame = Frame(self.Tk_UI, bg='#A97148')
        time_frame.pack(pady=20)

        time_label = Label(time_frame, text="Time allowed per move (seconds):", font=("Helvetica", 18), bg='#D9B693', fg='#582F2F')
        time_label.pack(side="left", padx=10)

        time_entry = Entry(time_frame, width=10, font=("Helvetica", 18))
        time_entry.pack(side="left")

        # Begin button
        ai_begin_button = Button(self.Tk_UI, text="Begin!", font=("Helvetica", 24, "bold"), bg='#A6E353', fg='#ECE7BD', command=lambda: self.check_if_ready(time_entry))
        ai_begin_button.pack(pady=60)

    def activate_button(self, button: Button, index):
        global side_picked

        self.ai_chosen_option = index

        if index == 0:
            side_picked = 0
        if index == 1:
            side_picked = choice([0, 1])
        if index == 2:
            side_picked = 1

        self.total_chosen_options.append(button)
        button.config(relief="sunken")
        if len(self.total_chosen_options) > 1 and self.total_chosen_options[-2] != button:
            self.total_chosen_options[-2].config(bg="white")
            self.total_chosen_options[-2].config(relief="raised")  # Then the last button is raised.
        button.config(bg="lightgreen")
        if len(self.total_chosen_options) > 2:
            self.total_chosen_options.pop(0)

    def check_if_ready(self, time_entry: Entry):

        self.remove_error_labels()

        time_allowed_per_move = time_entry.get()
        failed_start = 0

        try:
            int(time_allowed_per_move)
        except ValueError:
            self.create_error_label(error="You must input a valid time for the AI to think!")
            failed_start = 1

        if self.ai_chosen_option == -1:
            self.create_error_label(error="You must pick a side to play on!")
            failed_start = 1

        if failed_start == 0:
            make_board(self, "vsAI")

    def create_error_label(self, error):
        error_label = Label(self.Tk_UI, text=error, font=("Helvetica", 18), bg='#A56E54', fg='red')
        error_label.pack(side="top", pady=15)
        current_error_labels.append(error_label)

    def remove_error_labels(self):
        global current_error_labels
        for label in current_error_labels:
            label.destroy()
        current_error_labels = []

    def remove_ui(self):
        self.Tk_UI.destroy()

def return_to_main_ui(current_ui):
    if current_ui:
        current_ui.remove_ui()
    main_ui = HomePageUI(window=window)

def make_board(current_ui, play_mode):
    current_ui.remove_ui()
    board = Board(window=window, play_mode=play_mode)
    board.create_board()

def go_to_ai_ui(current_ui):
    current_ui.remove_ui()
    ai_options_ui = AIOptionsUI(window=window)

current_depth = 0

class AICode:

    global current_depth

    def __init__(self, current_position: dict, board_object: Board):

        self.current_position = current_position
        self.board = board_object

    def get_all_actions(self, position: dict):

        all_actions = []
        for square_notation in list(position.keys()):
            for available_square in Board.get_available_squares(square_notation, position):
                all_actions.append(square_notation + available_square)

        return all_actions
    
    def get_all_transition_models(self, position: dict):
        
        all_transition_models = []
        all_actions = self.get_all_actions(position)

        for action in all_actions:
            transition_model = position.copy()
            piece_to_move = transition_model.get(action[:1])
            transition_model.update({action[2:]: piece_to_move})

        fen_transition_model = Board.convert_to_fen(transition_model)
        all_transition_models.append(fen_transition_model)

